css:
.loader { --speed: var(--loader-speed); --accent: var(--loader-color); --accent-2: var(--loader-secondary-color); display: inline-flex; align-items: center; gap: 8px; padding: 12px 14px; border-radius: 12px; background: #020617; color: var(--accent); font: 700 14px/1 ui-monospace, SFMono-Regular, Menlo, monospace; box-shadow: inset 0 0 0 1px #ffffff18, 0 12px 30px #02061755; }
.prompt::before { content: "$ "; color: var(--accent-2); }
.dots { display: inline-flex; gap: 4px; }
.dots i { width: 5px; height: 5px; border-radius: 50%; background: currentColor; animation: terminal-dot calc(var(--speed) * 1) ease-in-out infinite; }
.dots i:nth-child(2) { animation-delay: .12s; } .dots i:nth-child(3) { animation-delay: .24s; }
.cursor { width: 9px; height: 18px; background: var(--accent-2); animation: terminal-cursor calc(var(--speed) * .8) steps(2,end) infinite; }
@keyframes terminal-dot { 50% { transform: translateY(-6px); color: var(--accent-2); } }
@keyframes terminal-cursor { 50% { opacity: 0; } }
